// Learn: Accept any number of int arguments.
int sum(String label, int... values) {
  int total = 0;
  // values acts like an array inside the method.
  for (int value : values) {
    total += value;
  }
  System.out.println(label + values.length);
  return total;
}

int score = sum("round", 4, 5, 6);
